Original-Code (TypeScript):
export function normalizedToFreq(n: number): number {
  return MIN_FREQ * Math.pow(MAX_FREQ / MIN_FREQ, Math.max(0, Math.min(1, n)))
}
// = 20 * pow(1000, clamp(n, 0, 1))

