Legacy-JUCE (C++):
void T5ynthFilter::setType(int type)
{
    if (type == currentType) return;
    currentType = type;
    auto juceType = juce::dsp::StateVariableTPTFilterType::lowpass;
    switch (type) {
        case 0: juceType = ...::lowpass; break;
        case 1: juceType = ...::highpass; break;
        case 2: juceType = ...::bandpass; break;
        default: break;
    }
    filter1.setType(juceType);
    filter2.setType(juceType);
}

