// Kein direktes Aequivalent — Web Audio verarbeitet
// den Graphen automatisch. Die Signal-Kette ist:
// input -> [dry: dryGain] ---------> outputNode
//       -> [wet: filter(s) -> wetGain] -> outputNode
// Gains werden per applyMix() gesetzt.

Legacy-JUCE (C++):
void T5ynthFilter::processBlock(juce::AudioBuffer<float>& buffer)
{
    if (!prepared) return;
    const int numChannels = buffer.getNumChannels();
    const int numSamples = buffer.getNumSamples();
    if (currentMix < 0.001f) return; // bypass
    const float halfPi = juce::MathConstants<float>::halfPi;
    const float wetGain = std::sin(currentMix * halfPi);
    const float dryGain = std::cos(currentMix * halfPi);
    if (dryGain < 0.001f) { // fully wet
        juce::dsp::AudioBlock<float> block(buffer);
        juce::dsp::ProcessContextReplacing<float> context(block);
        filter1.process(context);
        if (currentSlope == 1) {
            juce::dsp::ProcessContextReplacing<float> context2(block);
            filter2.process(context2);
        }
        return;
    }
    // Mixed: dry copy, filter, blend
    juce::AudioBuffer<float> dryBuffer(numChannels, numSamples);
    for (int ch = 0; ch < numChannels; ++ch)
        dryBuffer.copyFrom(ch, 0, buffer, ch, 0, numSamples);
    juce::dsp::AudioBlock<float> block(buffer);
    juce::dsp::ProcessContextReplacing<float> context(block);
    filter1.process(context);
    if (currentSlope == 1) {
        juce::dsp::ProcessContextReplacing<float> context2(block);
        filter2.process(context2);
    }
    for (int ch = 0; ch < numChannels; ++ch) {
        auto* wet = buffer.getWritePointer(ch);
        const auto* dry = dryBuffer.getReadPointer(ch);
        for (int i = 0; i < numSamples; ++i)
            wet[i] = dry[i] * dryGain + wet[i] * wetGain;
    }
}

void T5ynthFilter::reset()
{
    filter1.reset();
    filter2.reset();
}

Original-Code (TypeScript):
function dispose(): void {
  for (const fn of filterNodes) fn.disconnect()
  filterNodes = []
  if (dryGain) dryGain.disconnect()
  if (wetGain) wetGain.disconnect()
  if (inputNode) inputNode.disconnect()
  if (outputNode) outputNode.disconnect()
  dryGain = wetGain = inputNode = outputNode = null
  ctx = null
}

